// Normalize incoming task records to a stable schema
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  out.push({ json: {
    taskId: String(j.taskId ?? j.id ?? '').trim(),
    title: typeof j.title === 'string' ? j.title.trim() : j.title ?? null,
    source: j.source ?? 'api',
    receivedAt: new Date().toISOString(),
  } });
}
return out;

